import java.util.Scanner;

public class SafeBufferCopy {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");

        String input = scanner.nextLine();
        char[] buffer = new char[10];

        // Copy the input string into the buffer with bounds checking
        for (int i = 0; i < input.length() && i < buffer.length; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Input successfully copied to buffer: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
